import{_ as d,C as p,o as a,c as h,j as c,a as n,b as o,w as t,E as r,a3 as l,a2 as i}from"./chunks/framework.B72_uj9U.js";const v=JSON.parse('{"title":"OpenHands Architecture Deep Dive","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/openhands/architecture.md","filePath":"research/agents/openhands/architecture.md"}'),u={name:"research/agents/openhands/architecture.md"};function y(g,e,m,A,b,C){const s=p("Mermaid");return a(),h("div",null,[e[5]||(e[5]=c("h1",{id:"openhands-architecture-deep-dive",tabindex:"-1"},[n("OpenHands Architecture Deep Dive "),c("a",{class:"header-anchor",href:"#openhands-architecture-deep-dive","aria-label":'Permalink to "OpenHands Architecture Deep Dive"'},"​")],-1)),e[6]||(e[6]=c("h2",{id:"high-level-architecture",tabindex:"-1"},[n("High-Level Architecture "),c("a",{class:"header-anchor",href:"#high-level-architecture","aria-label":'Permalink to "High-Level Architecture"'},"​")],-1)),(a(),o(l,null,{default:t(()=>[r(s,{id:"mermaid-6",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20US%5B%22User%20%2F%20Server%22%5D%0A%20%20%20%20AC%5B%22AgentController%22%5D%0A%20%20%20%20ES%5B%22EventStream%5Cn(pub%2Fsub%20%2B%20persist)%22%5D%0A%20%20%20%20CA%5B%22CodeAct%20Agent%5Cn(LLM%20calls)%22%5D%0A%20%20%20%20RT%5B%22Runtime%20Layer%22%5D%0A%20%20%20%20AEC%5B%22ActionExecutionClient%20(host)%22%5D%0A%20%20%20%20AES%5B%22ActionExecutionServer%20(sandbox)%22%5D%0A%20%20%20%20BASH%5B%22Bash%20Shell%22%5D%0A%20%20%20%20JUP%5B%22Jupyter%20Kernel%22%5D%0A%20%20%20%20WEB%5B%22Browser%22%5D%0A%0A%20%20%20%20US%20--%3E%20AC%0A%20%20%20%20AC%20%3C--%3E%20ES%0A%20%20%20%20AC%20--%3E%20CA%0A%20%20%20%20CA%20--%3E%7C%22Actions%22%7C%20RT%0A%20%20%20%20ES%20--%3E%7C%22Events%22%7C%20RT%0A%20%20%20%20RT%20--%3E%20AEC%20--%3E%20AES%0A%20%20%20%20AES%20--%3E%20BASH%0A%20%20%20%20AES%20--%3E%20JUP%0A%20%20%20%20AES%20--%3E%20WEB%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[7]||(e[7]=i(`<h2 id="_1-eventstream-—-the-central-nervous-system" tabindex="-1">1. EventStream — The Central Nervous System <a class="header-anchor" href="#_1-eventstream-—-the-central-nervous-system" aria-label="Permalink to &quot;1. EventStream — The Central Nervous System&quot;">​</a></h2><p>Everything in OpenHands flows through the <strong>EventStream</strong> (<code>openhands/events/stream.py</code>). It is a thread-safe, persistent, pub/sub event bus that decouples every major component from every other. No component calls another directly; they all communicate by publishing events to, and subscribing to events from, this single stream.</p><h3 id="_1-1-design" tabindex="-1">1.1 Design <a class="header-anchor" href="#_1-1-design" aria-label="Permalink to &quot;1.1 Design&quot;">​</a></h3><p>EventStream extends <code>EventStore</code> and combines three responsibilities:</p><table tabindex="0"><thead><tr><th>Responsibility</th><th>Mechanism</th></tr></thead><tbody><tr><td><strong>Ordering</strong></td><td>Monotonically-incrementing integer <code>id</code> assigned on <code>add_event</code></td></tr><tr><td><strong>Persistence</strong></td><td>JSON serialization to a <code>FileStore</code> with pagination</td></tr><tr><td><strong>Pub/Sub</strong></td><td>Named subscribers with dedicated <code>ThreadPoolExecutor</code> per subscriber</td></tr></tbody></table><p>Subscribers are identified by well-known string IDs:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>AGENT_CONTROLLER  – the agent loop</span></span>
<span class="line"><span>RESOLVER          – resolver workflow</span></span>
<span class="line"><span>SERVER            – WebSocket / REST server</span></span>
<span class="line"><span>RUNTIME           – sandbox execution layer</span></span>
<span class="line"><span>MEMORY            – memory / recall subsystem</span></span>
<span class="line"><span>MAIN              – CLI / main entry point</span></span>
<span class="line"><span>TEST              – test harness</span></span></code></pre></div><h3 id="_1-2-event-anatomy" tabindex="-1">1.2 Event Anatomy <a class="header-anchor" href="#_1-2-event-anatomy" aria-label="Permalink to &quot;1.2 Event Anatomy&quot;">​</a></h3><p>Every event carries metadata set by the stream on ingestion:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> Event</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    id</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#6C7086;font-style:italic;">              # auto-incremented by EventStream</span></span>
<span class="line"><span style="color:#CDD6F4;">    timestamp</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#6C7086;font-style:italic;">       # ISO-8601, set on add_event</span></span>
<span class="line"><span style="color:#CDD6F4;">    source</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> EventSource  </span><span style="color:#6C7086;font-style:italic;"># AGENT | USER | ENVIRONMENT</span></span>
<span class="line"><span style="color:#CDD6F4;">    cause</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#6C7086;font-style:italic;">           # id of the parent event that triggered this one</span></span>
<span class="line"><span style="color:#CDD6F4;">    timeout</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#6C7086;font-style:italic;">         # optional deadline for observation response</span></span></code></pre></div><p>The <code>cause</code> field creates a causal graph: an <code>Observation</code> points back to the <code>Action</code> that produced it, enabling replay and debugging.</p><h3 id="_1-3-event-flow" tabindex="-1">1.3 Event Flow <a class="header-anchor" href="#_1-3-event-flow" aria-label="Permalink to &quot;1.3 Event Flow&quot;">​</a></h3>`,12)),(a(),o(l,null,{default:t(()=>[r(s,{id:"mermaid-74",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20P%5B%22Producer%20(Agent%2FUser%2FRuntime)%22%5D%0A%20%20%20%20AE%5B%22EventStream.add_event()%22%5D%0A%20%20%20%20AS%5B%22Assign%20id%2C%20timestamp%2C%20source%22%5D%0A%20%20%20%20SER%5B%22Serialize%20%E2%86%92%20JSON%20%E2%86%92%20FileStore%5Cn(with%20secret%20replacement)%22%5D%0A%20%20%20%20EN%5B%22Enqueue%20event%22%5D%0A%20%20%20%20BG%5B%22Background%20thread%20dequeues%22%5D%0A%20%20%20%20SA%5B%22Subscriber%20A%20callback%5Cn(own%20ThreadPoolExecutor)%22%5D%0A%20%20%20%20SB%5B%22Subscriber%20B%20callback%5Cn(own%20ThreadPoolExecutor)%22%5D%0A%20%20%20%20SC%5B%22Subscriber%20C%20callback%5Cn(own%20ThreadPoolExecutor)%22%5D%0A%0A%20%20%20%20P%20--%3E%20AE%20--%3E%20AS%20--%3E%20SER%20--%3E%20EN%20--%3E%20BG%0A%20%20%20%20BG%20--%3E%20SA%0A%20%20%20%20BG%20--%3E%20SB%0A%20%20%20%20BG%20--%3E%20SC%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[n(" Loading... ",-1)])]),_:1})),e[8]||(e[8]=i('<p>Key details:</p><ul><li><strong>Secret replacement</strong> scrubs credentials before events hit durable storage.</li><li><strong>Subscriber callbacks</strong> each run in their own <code>ThreadPoolExecutor</code>, so a slow subscriber cannot block the notification of others.</li><li><strong>Queue-based dispatch</strong> in a dedicated background thread decouples producers from consumers entirely.</li></ul><h3 id="_1-4-persistence-replay" tabindex="-1">1.4 Persistence &amp; Replay <a class="header-anchor" href="#_1-4-persistence-replay" aria-label="Permalink to &quot;1.4 Persistence &amp; Replay&quot;">​</a></h3><p>Events are serialized to JSON and written to a <code>FileStore</code> with pagination support. This enables:</p><ul><li><strong>Session replay</strong>: load all events and re-feed them through a controller.</li><li><strong>Crash recovery</strong>: resume from the last persisted event ID.</li><li><strong>Audit trail</strong>: every action the agent ever took is recorded.</li></ul><hr><h2 id="_2-action-observation-model" tabindex="-1">2. Action / Observation Model <a class="header-anchor" href="#_2-action-observation-model" aria-label="Permalink to &quot;2. Action / Observation Model&quot;">​</a></h2><p>All events are partitioned into exactly two families:</p><table tabindex="0"><thead><tr><th>Family</th><th>Semantics</th><th>Direction</th></tr></thead><tbody><tr><td><strong>Action</strong></td><td>An intent — something <em>should happen</em></td><td>Agent/User → Environment</td></tr><tr><td><strong>Observation</strong></td><td>A report — something <em>did happen</em></td><td>Environment → Agent/Controller</td></tr></tbody></table><p>An Action with <code>id=42</code> produces an Observation with <code>cause=42</code>. This pair forms the fundamental request/response unit of the system.</p><h3 id="_2-1-action-taxonomy" tabindex="-1">2.1 Action Taxonomy <a class="header-anchor" href="#_2-1-action-taxonomy" aria-label="Permalink to &quot;2.1 Action Taxonomy&quot;">​</a></h3><p>Actions live under <code>openhands/events/action/</code> and cover every capability the agent can invoke:</p><p><strong>Shell &amp; Code Execution</strong></p><table tabindex="0"><thead><tr><th>Action</th><th>Purpose</th><th>Key Fields</th></tr></thead><tbody><tr><td><code>CmdRunAction</code></td><td>Run a bash command</td><td><code>command</code>, <code>is_input</code> (for interactive stdin), <code>blocking</code>, <code>is_static</code></td></tr><tr><td><code>IPythonRunCellAction</code></td><td>Execute Python in Jupyter</td><td><code>code</code>, <code>include_extra</code></td></tr></tbody></table><p><strong>File Operations</strong></p><table tabindex="0"><thead><tr><th>Action</th><th>Purpose</th><th>Key Fields</th></tr></thead><tbody><tr><td><code>FileReadAction</code></td><td>Read a file</td><td><code>path</code>, <code>view_range</code> (OH_ACI mode)</td></tr><tr><td><code>FileWriteAction</code></td><td>Overwrite/create a file</td><td><code>path</code>, <code>content</code></td></tr><tr><td><code>FileEditAction</code></td><td>Surgical edit</td><td>Two modes: LLM-based diff vs. OH_ACI <code>str_replace</code>/<code>insert</code>/<code>create</code></td></tr></tbody></table><p><strong>Browser Automation</strong></p><table tabindex="0"><thead><tr><th>Action</th><th>Purpose</th></tr></thead><tbody><tr><td><code>BrowseURLAction</code></td><td>Navigate to a URL</td></tr><tr><td><code>BrowseInteractiveAction</code></td><td>Execute browser actions (click, type, scroll)</td></tr></tbody></table><p><strong>Agent Lifecycle &amp; Coordination</strong></p><table tabindex="0"><thead><tr><th>Action</th><th>Purpose</th></tr></thead><tbody><tr><td><code>AgentFinishAction</code></td><td>Signal task completion</td></tr><tr><td><code>AgentDelegateAction</code></td><td>Spawn a sub-agent for a sub-task</td></tr><tr><td><code>AgentThinkAction</code></td><td>Log internal chain-of-thought (no side effects)</td></tr><tr><td><code>MessageAction</code></td><td>Send a message to the user</td></tr><tr><td><code>SystemMessageAction</code></td><td>Inject a system-level prompt</td></tr></tbody></table><p><strong>Memory &amp; Context Management</strong></p><table tabindex="0"><thead><tr><th>Action</th><th>Purpose</th></tr></thead><tbody><tr><td><code>RecallAction</code></td><td>Query memory (type: <code>WORKSPACE_CONTEXT</code> or <code>KNOWLEDGE</code>)</td></tr><tr><td><code>CondensationAction</code></td><td>Trigger history condensation</td></tr><tr><td><code>CondensationRequestAction</code></td><td>Request condensation from the agent side</td></tr><tr><td><code>TaskTrackingAction</code></td><td>Manage internal task/todo lists</td></tr></tbody></table><p><strong>Integrations</strong></p><table tabindex="0"><thead><tr><th>Action</th><th>Purpose</th></tr></thead><tbody><tr><td><code>MCPAction</code></td><td>Call a tool exposed by an MCP server</td></tr></tbody></table><h3 id="_2-2-observation-taxonomy" tabindex="-1">2.2 Observation Taxonomy <a class="header-anchor" href="#_2-2-observation-taxonomy" aria-label="Permalink to &quot;2.2 Observation Taxonomy&quot;">​</a></h3><p>Observations under <code>openhands/events/observation/</code> mirror the actions:</p><table tabindex="0"><thead><tr><th>Observation</th><th>Corresponds To</th></tr></thead><tbody><tr><td><code>CmdOutputObservation</code></td><td><code>CmdRunAction</code> — stdout/stderr and exit code</td></tr><tr><td><code>IPythonRunCellObservation</code></td><td><code>IPythonRunCellAction</code> — cell output</td></tr><tr><td><code>FileReadObservation</code></td><td><code>FileReadAction</code> — file contents</td></tr><tr><td><code>FileWriteObservation</code></td><td><code>FileWriteAction</code> — confirmation</td></tr><tr><td><code>FileEditObservation</code></td><td><code>FileEditAction</code> — diff or result</td></tr><tr><td><code>BrowserOutputObservation</code></td><td>Browse actions — rendered page state</td></tr><tr><td><code>ErrorObservation</code></td><td>Any action that fails</td></tr><tr><td><code>AgentDelegateObservation</code></td><td><code>AgentDelegateAction</code> — sub-agent result</td></tr><tr><td><code>AgentStateChangedObservation</code></td><td>Controller state machine transitions</td></tr><tr><td><code>AgentCondensationObservation</code></td><td>Condensation results</td></tr><tr><td><code>RecallObservation</code></td><td><code>RecallAction</code> — retrieved memory fragments</td></tr><tr><td><code>LoopDetectionObservation</code></td><td>StuckDetector findings</td></tr><tr><td><code>MCPObservation</code></td><td><code>MCPAction</code> — tool call results</td></tr></tbody></table><hr><h2 id="_3-runtime-sandbox-architecture" tabindex="-1">3. Runtime / Sandbox Architecture <a class="header-anchor" href="#_3-runtime-sandbox-architecture" aria-label="Permalink to &quot;3. Runtime / Sandbox Architecture&quot;">​</a></h2><p>The runtime layer (<code>openhands/runtime/</code>) executes actions in an isolated environment. It uses a <strong>client–server split</strong> across a security boundary.</p><h3 id="_3-1-client–server-split" tabindex="-1">3.1 Client–Server Split <a class="header-anchor" href="#_3-1-client–server-split" aria-label="Permalink to &quot;3.1 Client–Server Split&quot;">​</a></h3>',31)),(a(),o(l,null,{default:t(()=>[r(s,{id:"mermaid-566",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20subgraph%20HOST%5B%22Host%20Process%22%5D%0A%20%20%20%20%20%20%20%20AEC%5B%22ActionExecutionClient%5Cn(translates%20Action%20to%20HTTP%20request%2C%5Cnreturns%20Observation)%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20DOCKER%5B%22Docker%20Container%20(or%20remote)%22%5D%0A%20%20%20%20%20%20%20%20AES%5B%22ActionExecutionServer%20(FastAPI)%5Cn%2Fexecute_action%20endpoint%5CnManages%20bash%20shell%2C%20Jupyter%20kernel%2C%5Cnbrowser%20instance%2C%20plugin%20system%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20AEC%20--%3E%7C%22HTTP%20%2Fexecute_action%22%7C%20AES%0A%20%20%20%20AES%20--%3E%7C%22JSON%20Observation%22%7C%20AEC%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[n(" Loading... ",-1)])]),_:1})),e[9]||(e[9]=i(`<p>The <strong>ActionExecutionClient</strong> (host side) translates <code>Action</code> objects into HTTP requests to the server. The <strong>ActionExecutionServer</strong> (<code>action_execution_server.py</code>) is a FastAPI application running <em>inside</em> the sandbox container. It owns the actual bash shell process, Jupyter kernel, and headless browser.</p><p>This split means the agent&#39;s host process never directly touches the sandboxed filesystem or processes — all interaction is mediated through a well-defined HTTP API.</p><h3 id="_3-2-runtime-implementations" tabindex="-1">3.2 Runtime Implementations <a class="header-anchor" href="#_3-2-runtime-implementations" aria-label="Permalink to &quot;3.2 Runtime Implementations&quot;">​</a></h3><p>The <code>Runtime</code> base class (<code>base.py</code>) defines the abstract interface. Concrete implementations differ only in <em>how they provision and connect to the sandbox</em>:</p><table tabindex="0"><thead><tr><th>Implementation</th><th>Where the sandbox runs</th><th>Provisioning</th></tr></thead><tbody><tr><td><code>DockerRuntime</code></td><td>Local Docker daemon</td><td><code>docker run</code> with custom image</td></tr><tr><td><code>LocalRuntime</code></td><td>Same host (no isolation)</td><td>Direct process execution</td></tr><tr><td><code>RemoteRuntime</code></td><td>Remote HTTP endpoint</td><td>API call to a provisioning service</td></tr><tr><td><code>ModalRuntime</code></td><td>Modal cloud platform</td><td>Modal API</td></tr><tr><td><code>RunloopRuntime</code></td><td>Runloop platform</td><td>Runloop API</td></tr></tbody></table><p>All implementations share the same ActionExecutionClient; only the connection target and lifecycle management differ.</p><h3 id="_3-3-image-tagging-system" tabindex="-1">3.3 Image Tagging System <a class="header-anchor" href="#_3-3-image-tagging-system" aria-label="Permalink to &quot;3.3 Image Tagging System&quot;">​</a></h3><p>Docker images follow a three-tag lifecycle for efficient rebuilds:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>versioned tag  →  lock tag  →  source tag</span></span>
<span class="line"><span>(oh_v0.17.0_...)  (oh_v0.17.0_lock_...) (oh_v0.17.0_source_...)</span></span></code></pre></div><p>This enables:</p><ul><li><strong>Lock tags</strong>: rebuild only when dependency locks change.</li><li><strong>Source tags</strong>: rebuild only when source code changes.</li><li><strong>Versioned tags</strong>: pin to a specific OpenHands release.</li></ul><h3 id="_3-4-plugin-system" tabindex="-1">3.4 Plugin System <a class="header-anchor" href="#_3-4-plugin-system" aria-label="Permalink to &quot;3.4 Plugin System&quot;">​</a></h3><p>The ActionExecutionServer supports plugins that extend its capabilities. Plugins are loaded at server startup and can register new endpoints or background services. The two built-in plugins are:</p><ul><li><strong>AgentSkillsPlugin</strong>: File-editing utilities available in the IPython kernel.</li><li><strong>JupyterPlugin</strong>: Manages the Jupyter kernel lifecycle.</li></ul><hr><h2 id="_4-agent-controller-—-the-orchestrator" tabindex="-1">4. Agent Controller — The Orchestrator <a class="header-anchor" href="#_4-agent-controller-—-the-orchestrator" aria-label="Permalink to &quot;4. Agent Controller — The Orchestrator&quot;">​</a></h2><p>The <code>AgentController</code> (<code>openhands/controller/agent_controller.py</code>, ~58KB) is the main orchestration loop. It is the largest single file in the codebase for good reason: it ties together the agent, the event stream, the runtime, and all safety/budgeting mechanisms.</p><h3 id="_4-1-core-loop" tabindex="-1">4.1 Core Loop <a class="header-anchor" href="#_4-1-core-loop" aria-label="Permalink to &quot;4.1 Core Loop&quot;">​</a></h3>`,18)),(a(),o(l,null,{default:t(()=>[r(s,{id:"mermaid-709",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20WE%5B%22Wait%20for%20new%20event%22%5D%0A%20%20%20%20US%5B%22Update%20State%20with%20incoming%20event%22%5D%0A%20%20%20%20CS%5B%22Call%20agent.step()%20%E2%86%92%20returns%20Action%22%5D%0A%20%20%20%20PA%5B%22Publish%20Action%20to%20EventStream%22%5D%0A%0A%20%20%20%20WE%20--%3E%20US%20--%3E%20CS%20--%3E%20PA%20--%3E%20WE%0A"})]),fallback:t(()=>[...e[3]||(e[3]=[n(" Loading... ",-1)])]),_:1})),e[10]||(e[10]=i('<p>The controller subscribes to <code>EventStream</code> with ID <code>AGENT_CONTROLLER</code>. When an <code>Observation</code> arrives (from the runtime or a sub-agent), it updates the agent&#39;s <code>State</code>, then calls <code>agent.step(state)</code> to get the next <code>Action</code>, which it publishes back to the stream.</p><h3 id="_4-2-state-management" tabindex="-1">4.2 State Management <a class="header-anchor" href="#_4-2-state-management" aria-label="Permalink to &quot;4.2 State Management&quot;">​</a></h3><p>The <code>State</code> object is the agent&#39;s working memory for a single session:</p><ul><li><strong>history</strong>: ordered list of Action/Observation pairs</li><li><strong>iteration count</strong>: how many agent steps have executed</li><li><strong>budget tracking</strong>: tokens consumed, cost accrued</li><li><strong>metrics</strong>: success/failure counts, timing data</li></ul><h3 id="_4-3-safety-mechanisms" tabindex="-1">4.3 Safety Mechanisms <a class="header-anchor" href="#_4-3-safety-mechanisms" aria-label="Permalink to &quot;4.3 Safety Mechanisms&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mechanism</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>max_iterations</strong></td><td>Hard cap on agent loop iterations</td></tr><tr><td><strong>budget_per_task</strong></td><td>Maximum dollar cost for a single task</td></tr><tr><td><strong>StuckDetector</strong></td><td>Detects repeated identical actions (loops) and emits <code>LoopDetectionObservation</code></td></tr><tr><td><strong>Security analysis</strong></td><td>Evaluates actions against a security policy before execution</td></tr><tr><td><strong>Timeout handling</strong></td><td>Actions can specify a <code>timeout</code>; controller enforces it</td></tr></tbody></table><h3 id="_4-4-agent-delegation" tabindex="-1">4.4 Agent Delegation <a class="header-anchor" href="#_4-4-agent-delegation" aria-label="Permalink to &quot;4.4 Agent Delegation&quot;">​</a></h3><p>A controller can spawn child controllers for sub-tasks:</p>',8)),(a(),o(l,null,{default:t(()=>[r(s,{id:"mermaid-804",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20PC%5B%22Parent%20Controller%22%5D%0A%20%20%20%20ADA%5B%22AgentDelegateAction%5Cn(agent%3D'BrowsingAgent'%2C%20task%3D'Find%20X')%22%5D%0A%20%20%20%20CC%5B%22Child%20Controller%20(new%20agent%2C%20shared%20EventStream)%22%5D%0A%20%20%20%20SL%5B%22...%20sub-agent%20loop%20...%22%5D%0A%20%20%20%20AFA%5B%22AgentFinishAction(result%3D'Found%20X%20at%20...')%22%5D%0A%20%20%20%20ADO%5B%22AgentDelegateObservation%5Cn(result%3D'Found%20X%20at%20...')%22%5D%0A%0A%20%20%20%20PC%20--%3E%20ADA%20--%3E%20CC%20--%3E%20SL%20--%3E%20AFA%20--%3E%20ADO%20--%3E%20PC%0A"})]),fallback:t(()=>[...e[4]||(e[4]=[n(" Loading... ",-1)])]),_:1})),e[11]||(e[11]=i(`<p>The child controller runs its own agent loop with its own state but publishes events to the same <code>EventStream</code>. When the child finishes, the parent receives an <code>AgentDelegateObservation</code> and continues.</p><h3 id="_4-5-replay-manager" tabindex="-1">4.5 Replay Manager <a class="header-anchor" href="#_4-5-replay-manager" aria-label="Permalink to &quot;4.5 Replay Manager&quot;">​</a></h3><p>The <code>ReplayManager</code> enables session replay: given a persisted event stream, it can reconstruct the agent&#39;s state up to any point and optionally continue execution from there. This powers the &quot;resume session&quot; feature.</p><hr><h2 id="_5-agent-architecture" tabindex="-1">5. Agent Architecture <a class="header-anchor" href="#_5-agent-architecture" aria-label="Permalink to &quot;5. Agent Architecture&quot;">​</a></h2><h3 id="_5-1-base-class-registry" tabindex="-1">5.1 Base Class &amp; Registry <a class="header-anchor" href="#_5-1-base-class-registry" aria-label="Permalink to &quot;5.1 Base Class &amp; Registry&quot;">​</a></h3><p>The <code>Agent</code> base class (<code>openhands/controller/agent.py</code>) uses a <strong>registry pattern</strong>:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> Agent</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">    _registry</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;font-style:italic;"> dict</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;font-style:italic;">str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> type</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">Agent</span><span style="color:#9399B2;">]]</span><span style="color:#94E2D5;"> =</span><span style="color:#9399B2;"> {}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    @classmethod</span></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> register</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">cls</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> name</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> agent_cls</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;font-style:italic;"> type</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">Agent</span><span style="color:#9399B2;">]):</span></span>
<span class="line"><span style="color:#CDD6F4;">        cls</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">_registry</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">name</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;"> =</span><span style="color:#CDD6F4;"> agent_cls</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    @classmethod</span></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> get_cls</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">cls</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> name</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#EBA0AC;font-style:italic;"> type</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">Agent</span><span style="color:#9399B2;">]:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CDD6F4;"> cls</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">_registry</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">name</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    @abstractmethod</span></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> step</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> state</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;"> State</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#CDD6F4;"> Action</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;&quot;&quot;Given current state, decide the next action.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">        ...</span></span></code></pre></div><p>Every agent must implement <code>step(state) → Action</code>. The registry allows agent selection by name at configuration time.</p><h3 id="_5-2-mcp-tool-integration" tabindex="-1">5.2 MCP Tool Integration <a class="header-anchor" href="#_5-2-mcp-tool-integration" aria-label="Permalink to &quot;5.2 MCP Tool Integration&quot;">​</a></h3><p>Agents can receive tools from external MCP (Model Context Protocol) servers:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CDD6F4;">agent</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">set_mcp_tools</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tools</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;font-style:italic;"> list</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">MCPTool</span><span style="color:#9399B2;">])</span></span></code></pre></div><p>These tools are added to the agent&#39;s available tool set alongside the built-in tools. When the LLM selects an MCP tool, a <code>MCPAction</code> is emitted, routed to the appropriate MCP server, and the response comes back as an <code>MCPObservation</code>.</p><hr><h2 id="_6-codeactagent-—-the-primary-agent" tabindex="-1">6. CodeActAgent — The Primary Agent <a class="header-anchor" href="#_6-codeactagent-—-the-primary-agent" aria-label="Permalink to &quot;6. CodeActAgent — The Primary Agent&quot;">​</a></h2><p>The <code>CodeActAgent</code> is the default and most capable agent in OpenHands. It implements the <strong>CodeAct</strong> paradigm: using LLM function-calling (tool use) to map natural language instructions to concrete environment actions.</p><h3 id="_6-1-tool-set" tabindex="-1">6.1 Tool Set <a class="header-anchor" href="#_6-1-tool-set" aria-label="Permalink to &quot;6.1 Tool Set&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Maps To</th><th>Description</th></tr></thead><tbody><tr><td><code>bash</code></td><td><code>CmdRunAction</code></td><td>Execute shell commands</td></tr><tr><td><code>ipython</code></td><td><code>IPythonRunCellAction</code></td><td>Run Python code in Jupyter</td></tr><tr><td><code>browser</code></td><td><code>BrowseInteractiveAction</code></td><td>Interact with web pages</td></tr><tr><td><code>edit</code></td><td><code>FileEditAction</code></td><td>Edit files (str_replace or LLM-based)</td></tr><tr><td><code>think</code></td><td><code>AgentThinkAction</code></td><td>Chain-of-thought with no side effects</td></tr><tr><td><code>finish</code></td><td><code>AgentFinishAction</code></td><td>Declare task complete</td></tr><tr><td><code>condensation_request</code></td><td><code>CondensationRequestAction</code></td><td>Request history condensation</td></tr><tr><td><code>task_tracker</code></td><td><code>TaskTrackingAction</code></td><td>Manage internal todo list</td></tr></tbody></table><h3 id="_6-2-conversation-construction" tabindex="-1">6.2 Conversation Construction <a class="header-anchor" href="#_6-2-conversation-construction" aria-label="Permalink to &quot;6.2 Conversation Construction&quot;">​</a></h3><p>The <code>ConversationMemory</code> component assembles the LLM prompt from the event history:</p><ol><li><strong>System message</strong>: Agent instructions, available tools, environment description.</li><li><strong>History</strong>: Action/Observation pairs formatted as assistant/tool messages.</li><li><strong>Condensed segments</strong>: Older history may be replaced with summaries.</li><li><strong>Prompt caching</strong>: For Anthropic models, cache breakpoints are inserted to avoid re-processing unchanged prefix tokens.</li></ol><h3 id="_6-3-history-condensation" tabindex="-1">6.3 History Condensation <a class="header-anchor" href="#_6-3-history-condensation" aria-label="Permalink to &quot;6.3 History Condensation&quot;">​</a></h3><p>As conversations grow, the <code>Condenser</code> compresses older history to stay within context limits. Strategies include:</p><ul><li><strong>LLM summarization</strong>: Ask the LLM to summarize older turns.</li><li><strong>Sliding window</strong>: Keep only the N most recent turns.</li><li><strong>Hybrid</strong>: Summarize old history, keep recent turns verbatim.</li></ul><p>The agent can also <em>request</em> condensation via <code>CondensationRequestAction</code> when it detects its context is getting large.</p><h3 id="_6-4-step-function-flow" tabindex="-1">6.4 Step Function Flow <a class="header-anchor" href="#_6-4-step-function-flow" aria-label="Permalink to &quot;6.4 Step Function Flow&quot;">​</a></h3><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Simplified CodeActAgent.step()</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> step</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> state</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;"> State</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#CDD6F4;"> Action</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # 1. Build messages from conversation memory</span></span>
<span class="line"><span style="color:#CDD6F4;">    messages </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">conversation_memory</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">build_messages</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # 2. Call LLM with function-calling enabled</span></span>
<span class="line"><span style="color:#CDD6F4;">    response </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">llm</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">completion</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        messages</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        tools</span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">tools</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;">       # bash, ipython, edit, browser, ...</span></span>
<span class="line"><span style="color:#9399B2;">    )</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # 3. Parse tool call from response</span></span>
<span class="line"><span style="color:#CDD6F4;">    tool_call </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> response</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">choices</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;font-style:italic;">0</span><span style="color:#9399B2;">].</span><span style="color:#CDD6F4;">message</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">tool_calls</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;font-style:italic;">0</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # 4. Map to Action</span></span>
<span class="line"><span style="color:#CDD6F4;">    action </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">action_from_tool_call</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tool_call</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> action</span></span></code></pre></div><hr><h2 id="_7-data-flow-—-end-to-end" tabindex="-1">7. Data Flow — End to End <a class="header-anchor" href="#_7-data-flow-—-end-to-end" aria-label="Permalink to &quot;7. Data Flow — End to End&quot;">​</a></h2><p>A complete cycle for a user request like <em>&quot;Fix the bug in auth.py&quot;</em>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>1. User sends message</span></span>
<span class="line"><span>   └─▶ MessageAction(content=&quot;Fix the bug in auth.py&quot;, source=USER)</span></span>
<span class="line"><span>        └─▶ EventStream.add_event()</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. AgentController receives event</span></span>
<span class="line"><span>   └─▶ Updates State with new message</span></span>
<span class="line"><span>   └─▶ Calls CodeActAgent.step(state)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. CodeActAgent builds prompt, calls LLM</span></span>
<span class="line"><span>   └─▶ LLM returns tool_call: bash(command=&quot;cat auth.py&quot;)</span></span>
<span class="line"><span>   └─▶ Returns CmdRunAction(command=&quot;cat auth.py&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Controller publishes CmdRunAction to EventStream</span></span>
<span class="line"><span>   └─▶ Runtime (subscriber) picks up the action</span></span>
<span class="line"><span>   └─▶ ActionExecutionClient sends HTTP POST to sandbox server</span></span>
<span class="line"><span>   └─▶ ActionExecutionServer runs \`cat auth.py\` in bash</span></span>
<span class="line"><span>   └─▶ Returns CmdOutputObservation(content=&quot;&lt;file contents&gt;&quot;, exit_code=0)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. Runtime publishes CmdOutputObservation to EventStream</span></span>
<span class="line"><span>   └─▶ Controller receives it, updates State</span></span>
<span class="line"><span>   └─▶ Calls CodeActAgent.step(state) again</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. Agent sees file contents, decides to edit</span></span>
<span class="line"><span>   └─▶ Returns FileEditAction(path=&quot;auth.py&quot;, changes=...)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. Cycle continues until AgentFinishAction</span></span></code></pre></div><hr><h2 id="_8-key-design-patterns" tabindex="-1">8. Key Design Patterns <a class="header-anchor" href="#_8-key-design-patterns" aria-label="Permalink to &quot;8. Key Design Patterns&quot;">​</a></h2><h3 id="_8-1-event-sourcing" tabindex="-1">8.1 Event Sourcing <a class="header-anchor" href="#_8-1-event-sourcing" aria-label="Permalink to &quot;8.1 Event Sourcing&quot;">​</a></h3><p>The entire system state can be reconstructed from the event stream. There is no mutable shared state outside of <code>EventStream</code>. This enables replay, debugging, and crash recovery.</p><h3 id="_8-2-subscriber-isolation" tabindex="-1">8.2 Subscriber Isolation <a class="header-anchor" href="#_8-2-subscriber-isolation" aria-label="Permalink to &quot;8.2 Subscriber Isolation&quot;">​</a></h3><p>Each <code>EventStream</code> subscriber gets its own <code>ThreadPoolExecutor</code>. A misbehaving subscriber (slow, crashing) cannot affect others. This is critical because the runtime, agent controller, and server all subscribe to the same stream.</p><h3 id="_8-3-security-boundary" tabindex="-1">8.3 Security Boundary <a class="header-anchor" href="#_8-3-security-boundary" aria-label="Permalink to &quot;8.3 Security Boundary&quot;">​</a></h3><p>The client–server split in the runtime creates a hard security boundary. The host process (agent, controller, LLM calls) never directly accesses the sandboxed filesystem or processes. All interaction goes through a narrow HTTP API, which can be audited and rate-limited.</p><h3 id="_8-4-registry-pattern" tabindex="-1">8.4 Registry Pattern <a class="header-anchor" href="#_8-4-registry-pattern" aria-label="Permalink to &quot;8.4 Registry Pattern&quot;">​</a></h3><p>Agents, runtimes, and condensers all use a registry pattern. Components register themselves by name, and the system instantiates them by configuration string. This makes the system extensible without modifying core code.</p><h3 id="_8-5-causal-event-linking" tabindex="-1">8.5 Causal Event Linking <a class="header-anchor" href="#_8-5-causal-event-linking" aria-label="Permalink to &quot;8.5 Causal Event Linking&quot;">​</a></h3><p>The <code>cause</code> field on events creates a directed acyclic graph of causality. Given any observation, you can trace back through the chain of actions and observations that led to it. This is invaluable for debugging agent behavior and understanding why the agent took a particular path.</p><hr><h2 id="_9-summary" tabindex="-1">9. Summary <a class="header-anchor" href="#_9-summary" aria-label="Permalink to &quot;9. Summary&quot;">​</a></h2><p>OpenHands&#39; architecture is built on a small number of powerful abstractions:</p><table tabindex="0"><thead><tr><th>Abstraction</th><th>Role</th></tr></thead><tbody><tr><td><strong>EventStream</strong></td><td>Decoupled, persistent, thread-safe communication bus</td></tr><tr><td><strong>Action/Observation</strong></td><td>Typed, causal request/response pairs</td></tr><tr><td><strong>Runtime</strong></td><td>Isolated execution via client–server split</td></tr><tr><td><strong>AgentController</strong></td><td>Orchestration loop with safety guardrails</td></tr><tr><td><strong>Agent (CodeAct)</strong></td><td>LLM-powered decision-making via function calling</td></tr></tbody></table><p>The event-sourced design means every session is fully reproducible. The sandbox architecture means agent actions are isolated and auditable. The pub/sub model means components can evolve independently. Together, these patterns create a system that is both powerful and maintainable.</p>`,48))])}const B=d(u,[["render",y]]);export{v as __pageData,B as default};
